options.customCss:
:root {

	/* Typography */
	--font-family: 'Inter', 'Open Sans', sans-serif;
	--font-weight-normal: 400;
	--font-weight-medium: 500;
	--font-weight-bold: 600;

	--font-size-body: 14px;
	--font-size-label: 14px;
	--font-size-input: 14px;
	--font-size-header: 22px;
	--font-size-paragraph: 15px;
	--font-size-link: 13px;
	--font-size-error: 12px;

	--font-size-html-h1: 30px;
	--font-size-html-h2: 24px;
	--font-size-html-h3: 18px;
	--font-size-html-h4: 16px;
	--font-size-html-h5: 14px;
	--font-size-html-h6: 12px;

	--font-size-subheader: 15px;


	/* Core Colors */
	--color-background: #f5f7fb;
	--color-surface: #ffffff;
	--color-border: #e4e7ec;

	/* Text */
	--color-header: #1f2937;
	--color-label: #344054;
	--color-text: #475467;
	--color-muted: #98a2b3;

	/* Primary Theme */
	--color-primary: #635bff;
	--color-primary-hover: #5146e5;
	--color-primary-light: #eef2ff;

	/* Links */
	--color-link: #635bff;
	--color-html-link: #635bff;

	/* Inputs */
	--color-input-border: #d0d5dd;
	--color-input-text: #344054;
	--color-input-bg: #ffffff;

	--color-focus-border: #635bff;
	--color-focus-shadow: rgba(99, 91, 255, 0.25);

	/* Buttons */
	--color-submit-btn-bg: #635bff;
	--color-submit-btn-hover: #5146e5;
	--color-submit-btn-text: #ffffff;

	--color-clear-button-bg: #667085;

	/* Alerts */
	--color-test-notice-text: #b54708;
	--color-test-notice-bg: #fff7ed;
	--color-test-notice-border: #fed7aa;

	--color-error: #d92d20;
	--color-required: #ff5a3c;

	/* HTML content */
	--color-html-text: #475467;
	--color-header-subtext: #667085;


	/* Border Radius */
	--border-radius-card: 12px;
	--border-radius-input: 8px;
	--border-radius-clear-btn: 50%;


	/* Spacing */
	--padding-container-top: 32px;
	--padding-card: 28px;
	--padding-form-input: 14px;

	--padding-test-notice-vertical: 12px;
	--padding-test-notice-horizontal: 20px;

	--margin-bottom-card: 20px;


	/* Layout */
	--container-width: 460px;
	--submit-btn-height: 48px;
	--checkbox-size: 18px;


	/* Shadows (more modern depth) */
	--box-shadow-card: 
		0 4px 8px rgba(16, 24, 40, 0.04),
		0 12px 24px rgba(16, 24, 40, 0.08);

	--box-shadow-focus:
		0 0 0 3px var(--color-focus-shadow);


	/* Misc */
	--opacity-placeholder: 0.6;
}
